        "  ' \"$ROOT_DIR\"",
        "}",
        "",
        "validate_short_name \"$SHORT_NAME\" || {",
        "  echo \"{\\\"error\\\":\\\"short_name must be a concise alias with 1 to 3 lowercase lexical tokens\\\"}\" >&2",
        "  exit 1",
