        "  MANIFEST_GIT_MODE=\"$(node -e 'const fs=require(\"fs\"); const manifest=JSON.parse(fs.readFileSync(process.argv[1],\"utf8\")); process.stdout.write(String(manifest.git?.mode ?? \"off\"));' \"$ROOT_DIR/.pgg/project.json\")\"",
